/* Source: styles/packages/button/src/ — Honeypot */
.hp-button {
  font: 500 16px/16px 'DM Sans'; /* hp-typography__button--medium */
  height: 40px;       /* $hp-button-size */
  padding: 0 32px;    /* $hp-space-x-large */
  border-radius: 50px; /* $hp-button-border-basic-radius */
  border: none;
  min-width: 64px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}
.hp-button--primary        { background: #4B82FA; color: #fff; } /* $dt-primary-main */
.hp-button--primary:hover  { background: #1F60ED; } /* $dt-primary-middle */
.hp-button--primary:active { background: #0052CC; } /* $dt-primary-dark */
.hp-button--secondary      { background: #fff; color: #4B82FA; border: 2px solid #1F60ED; }
.hp-button--tertiary       { background: #fff; color: #39414D; border: 2px solid #C5D2E7; }
.hp-button--danger         { background: #FF5630; color: #fff; } /* $dt-feedback-r3 */
.hp-button--tall           { height: 56px; } /* $hp-button-tall-size, submit actions */
.hp-button:disabled        { background: #E1E6ED; color: #8FA0BA; }
